BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?pkg ?name ?comment WHERE {
  ?pkg rdf:type vocab:package .
  ?pkg vocab:NamedElement_name ?name .
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("APS")))
  OPTIONAL {
    ?pkg vocab:Element_ownedComment ?commentElem .
    ?commentElem vocab:Comment_body ?comment .
  }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?stereotype ?stereoName ?classifier WHERE {
  VALUES ?stereotype {
    <http://api.koneksys.com/cameo/TMT/instance%20specification/_18_0_2_b4c02e1_1422576771454_116497_83855>
    <http://api.koneksys.com/cameo/TMT/instance%20specification/_17_0_2_3_b4c02e1_1401220694902_311817_88895>
    <http://api.koneksys.com/cameo/TMT/instance%20specification/_18_0_2_baa02e2_1421730853649_492528_81916>
  }
  OPTIONAL { ?stereotype vocab:NamedElement_name ?stereoName }
  OPTIONAL { ?stereotype vocab:InstanceSpecification_classifier ?classifier }
  OPTIONAL { ?classifier vocab:NamedElement_name ?classifierName }
}
LIMIT 50
